/* ─────────────────── CONSTANTS ─────────────────── */
const ALLOWED_KATEGORI = ["B", "C", "D", "E", "F", "H"];

const KATEGORI_NAMES = {
  B: "B — Pertambangan dan Penggalian",
  C: "C — Industri Pengolahan",
  D: "D — Pengadaan Listrik, Gas, Uap/Air Panas",
  E: "E — Pengelolaan Air, Sampah, Limbah",
  F: "F — Konstruksi",
  H: "H — Transportasi dan Pergudangan",
};

const META = {
  totalRecords: DATA.length,
  uniqueKbli: [...new Set(DATA.map((r) => r.kode))].length,
  uniqueKategori: ALLOWED_KATEGORI.filter((l) =>
    DATA.some((r) => r.kat.startsWith(l)),
  ).length,
};

/* ─────────────────── HELPERS ─────────────────── */
function norm(x) {
  return String(x || "")
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}
function compact(x, n = 140) {
  const s = String(x || "")
    .replace(/\s+/g, " ")
    .trim();
  return s.length > n ? s.slice(0, n - 1) + "…" : s;
}
function kategoriLetter(row) {
  return (row.kat || "").match(/^\s*([A-Z])/)?.[1] || "";
}
function subkategoriCode(row) {
  return (row.kode || "").slice(0, 2);
}
function subkategoriLabel(row) {
  const kat = row.kat || "";
  return kat.includes("/")
    ? kat.split("/").pop().trim()
    : kat.replace(/^\s*[A-Z]\s*[–-]\s*/, "").trim();
}
function unique(arr) {
  return [...new Set(arr.filter(Boolean))].sort((a, b) =>
    String(a).localeCompare(String(b), "id"),
  );
}

/* ─────────────────── SUB-COMPONENTS ─────────────────── */
function FieldLabel({ children, icon: Icon }) {
  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: 6,
        fontSize: 11,
        fontWeight: 700,
        letterSpacing: "0.08em",
        textTransform: "uppercase",
        color: "#64748b",
        marginBottom: 7,
      }}
    >
      {Icon && <Icon size={10} />}
      {children}
    </div>
  );
}

function SelectBox({ value, onChange, options, placeholder, disabled }) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const ref = useRef(null);

  useEffect(() => {
    function handler(e) {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    }
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const filtered = useMemo(
    () =>
      query.trim()
        ? options.filter((o) => norm(o.label).includes(norm(query)))
        : options,
    [options, query],
  );

  const selected = options.find((o) => o.value === value);

  return (
    <div ref={ref} style={{ position: "relative" }}>
      <button
        disabled={disabled}
        onClick={() => {
          if (!disabled) {
            setOpen((o) => !o);
            setQuery("");
          }
        }}
        style={{
          width: "100%",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "11px 14px",
          borderRadius: 12,
          border: "2px solid",
          borderColor: open ? "#0f766e" : value ? "#0f766e" : "#e2e8f0",
          background: disabled ? "#f8fafc" : "#fff",
          color: value ? "#172033" : "#94a3b8",
          fontSize: 14,
          fontWeight: value ? 600 : 400,
          cursor: disabled ? "not-allowed" : "pointer",
          fontFamily: "inherit",
          textAlign: "left",
          boxShadow: open ? "0 0 0 4px rgba(15,118,110,0.12)" : "none",
          transition: "all 0.2s",
        }}
      >
        <span
          style={{
            overflow: "hidden",
            textOverflow: "ellipsis",
            whiteSpace: "nowrap",
            flex: 1,
          }}
        >
          {selected ? compact(selected.label, 60) : placeholder}
        </span>
        {open ? (
          <ChevronUp
            size={16}
            color="#0f766e"
            style={{ flexShrink: 0, marginLeft: 8 }}
          />
        ) : (
          <ChevronDown
            size={16}
            color="#94a3b8"
            style={{ flexShrink: 0, marginLeft: 8 }}
          />
        )}
      </button>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, y: -8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -8 }}
            transition={{ duration: 0.15 }}
            style={{
              position: "absolute",
              top: "calc(100% + 6px)",
              left: 0,
              right: 0,
              zIndex: 999,
              background: "#fff",
              borderRadius: 14,
              border: "1.5px solid rgba(15,118,110,0.25)",
              boxShadow: "0 20px 50px rgba(15,23,42,0.14)",
              overflow: "hidden",
            }}
          >
            <div
              style={{ padding: "8px 10px", borderBottom: "1px solid #f1f5f9" }}
            >
              <input
                autoFocus
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="Cari..."
                style={{
                  width: "100%",
                  border: "1px solid #e2e8f0",
                  borderRadius: 9,
                  padding: "8px 12px",
                  fontSize: 13,
                  outline: "none",
                  fontFamily: "inherit",
                  background: "#f8fafc",
                  boxSizing: "border-box",
                }}
                onFocus={(e) => {
                  e.target.style.borderColor = "#0f766e";
                  e.target.style.boxShadow = "0 0 0 3px rgba(15,118,110,0.1)";
                }}
                onBlur={(e) => {
                  e.target.style.borderColor = "#e2e8f0";
                  e.target.style.boxShadow = "none";
                }}
              />
            </div>
            <div style={{ maxHeight: 260, overflowY: "auto" }}>
              {filtered.length === 0 ? (
                <div
                  style={{
                    padding: "20px 16px",
                    textAlign: "center",
                    fontSize: 13,
                    color: "#94a3b8",
                  }}
                >
                  Tidak ditemukan
                </div>
              ) : (
                filtered.map((opt) => (
                  <div
                    key={opt.value}
                    onClick={() => {
                      onChange(opt.value);
                      setOpen(false);
                      setQuery("");
                    }}
                    style={{
                      padding: "10px 14px",
                      cursor: "pointer",
                      fontSize: 13,
                      background:
                        opt.value === value ? "#ecfdf5" : "transparent",
                      color: opt.value === value ? "#065f46" : "#334155",
                      fontWeight: opt.value === value ? 700 : 400,
                      transition: "background 0.1s",
                      borderBottom: "1px solid #f8fafc",
                    }}
                    onMouseEnter={(e) => {
                      if (opt.value !== value)
                        e.currentTarget.style.background = "#f8fafc";
                    }}
                    onMouseLeave={(e) => {
                      if (opt.value !== value)
                        e.currentTarget.style.background = "transparent";
                    }}
                  >
                    {opt.label}
                  </div>
                ))
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

function Chip({ children, variant = "default" }) {
  const styles = {
    default: { bg: "#f8fafc", border: "#e2e8f0", color: "#475569" },
    green: { bg: "#ecfdf5", border: "#bbf7d0", color: "#166534" },
    teal: { bg: "#f0fdfa", border: "#99f6e4", color: "#0f766e" },
    orange: { bg: "#fff7ed", border: "#fed7aa", color: "#9a3412" },
    blue: { bg: "#eff6ff", border: "#bfdbfe", color: "#1e40af" },
  };
  const s = styles[variant] || styles.default;
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: 4,
        padding: "4px 9px",
        borderRadius: 999,
        background: s.bg,
        border: `1px solid ${s.border}`,
        color: s.color,
        fontSize: 11.5,
        fontWeight: 700,
      }}
    >
      {children}
    </span>
  );
}

function DetailField({ label, value, accent }) {
  if (!value || String(value).trim() === "" || String(value).trim() === "—")
    return null;
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: "200px 1fr",
        gap: 12,
        padding: "12px 16px",
        borderBottom: "1px solid #f1f5f9",
      }}
    >
      <div style={{ color: "#475569", fontWeight: 700, fontSize: 13 }}>
        {label}
      </div>
      <div
        style={{
          color: accent || "#1f2937",
          lineHeight: 1.65,
          fontSize: 13.5,
          whiteSpace: "pre-line",
        }}
      >
        {String(value).trim()}
      </div>
    </div>
  );
}

function DetailSection({ title, children }) {
  return (
    <div
      style={{
        border: "1px solid #e2e8f0",
        borderRadius: 16,
        background: "#fff",
        overflow: "hidden",
      }}
    >
      <div
        style={{
          padding: "11px 16px",
          background: "#f8fafc",
          borderBottom: "1px solid #e2e8f0",
          fontSize: 14,
          fontWeight: 800,
          color: "#334155",
          letterSpacing: "-0.01em",
        }}
      >
        {title}
      </div>
      {children}
    </div>
  );
}

function CopyButton({ text }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    } catch {}
  };
  return (
    <button
      onClick={handleCopy}
      style={{
        display: "flex",
        alignItems: "center",
        gap: 6,
        padding: "7px 13px",
        borderRadius: 999,
        border: "1.5px solid #e2e8f0",
        background: "#fff",
        color: "#64748b",
        fontSize: 12,
        fontWeight: 600,
        cursor: "pointer",
        fontFamily: "inherit",
        transition: "all 0.2s",
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.borderColor = "#0f766e";
        e.currentTarget.style.color = "#0f766e";
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.borderColor = "#e2e8f0";
        e.currentTarget.style.color = "#64748b";
      }}
    >
      {copied ? <Check size={13} color="#059669" /> : <Copy size={13} />}
      {copied ? "Disalin" : "Salin"}
    </button>
  );
}

/* ─────────────────── MAIN COMPONENT ─────────────────── */
export default function TaxBeaMasuk() {
  /* Input states */
  const [kategori, setKategori] = useState("");
  const [subkategori, setSubkategori] = useState("");
  const [bidangUsaha, setBidangUsaha] = useState("");
  const [jenisBrg, setJenisBrg] = useState("");
  const [lokasi, setLokasi] = useState("");
  const [kawasan, setKawasan] = useState("");
  const [hs, setHs] = useState("");
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [expandedDetail, setExpandedDetail] = useState(true);
  const resultsRef = useRef(null);

  /* ── Derived options ── */
  const kategoriOptions = useMemo(
    () =>
      ALLOWED_KATEGORI.filter((l) =>
        DATA.some((r) => kategoriLetter(r) === l),
      ).map((l) => ({ value: l, label: KATEGORI_NAMES[l] || l })),
    [],
  );

  const subkategoriOptions = useMemo(() => {
    if (!kategori) return [];
    const map = new Map();
    DATA.filter((r) => kategoriLetter(r) === kategori).forEach((r) => {
      const c = subkategoriCode(r);
      if (c && !map.has(c)) map.set(c, `${c} — ${subkategoriLabel(r)}`);
    });
    return [...map.entries()]
      .sort((a, b) => a[0].localeCompare(b[0], "id"))
      .map(([v, l]) => ({ value: v, label: l }));
  }, [kategori]);

  const bidangUsahaOptions = useMemo(() => {
    if (!kategori || !subkategori) return [];
    const map = new Map();
    DATA.filter(
      (r) => kategoriLetter(r) === kategori && r.kode.startsWith(subkategori),
    ).forEach((r) => {
      if (!map.has(r.kode)) map.set(r.kode, `${r.kode} — ${r.bidang}`);
    });
    return [...map.entries()]
      .sort((a, b) => a[0].localeCompare(b[0], "id"))
      .map(([v, l]) => ({ value: v, label: l }));
  }, [kategori, subkategori]);

  const jenisBrgOptions = useMemo(() => {
    if (!bidangUsaha) return [];
    return unique(
      DATA.filter((r) => r.kode === bidangUsaha).map((r) => r.jenisBrg),
    ).map((v) => ({ value: v, label: v }));
  }, [bidangUsaha]);

  const isLocked = kategori && subkategori && bidangUsaha;

  /* ── Filter logic ── */
  const filteredResults = useMemo(() => {
    if (!isLocked) return [];
    return DATA.filter((r) => {
      if (kategoriLetter(r) !== kategori) return false;
      if (!r.kode.startsWith(subkategori)) return false;
      if (r.kode !== bidangUsaha) return false;
      if (jenisBrg && r.jenisBrg !== jenisBrg) return false;
      if (
        lokasi &&
        !norm(r.kat).includes(norm(lokasi)) &&
        !norm(r.bidang).includes(norm(lokasi))
      )
        return false;
      if (
        kawasan &&
        !norm(r.kode).includes(norm(kawasan)) &&
        !norm(r.bidang).includes(norm(kawasan))
      )
        return false;
      if (hs && !norm(r.regulasi).includes(norm(hs))) return false;
      return true;
    });
  }, [
    kategori,
    subkategori,
    bidangUsaha,
    jenisBrg,
    lokasi,
    kawasan,
    hs,
    isLocked,
  ]);

  const safeIndex = Math.min(selectedIndex, filteredResults.length - 1);
  const selected = filteredResults[safeIndex < 0 ? 0 : safeIndex];

  useEffect(() => {
    setSelectedIndex(0);
  }, [filteredResults.length, bidangUsaha]);

  /* ── Reset ── */
  function resetAll() {
    setKategori("");
    setSubkategori("");
    setBidangUsaha("");
    setJenisBrg("");
    setLokasi("");
    setKawasan("");
    setHs("");
    setSelectedIndex(0);
  }

  /* ── Download ── */
  function handleDownload() {
    if (!filteredResults.length) return;
    const blob = new Blob([JSON.stringify(filteredResults, null, 2)], {
      type: "application/json",
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "hasil_pembebasan_bm.json";
    a.click();
    URL.revokeObjectURL(url);
  }

  function summarize(r) {
    return [
      `KBLI: ${r.kode} — ${r.bidang}`,
      `Kategori: ${r.kat}`,
      `Jenis Barang: ${r.jenisBrg}`,
      `Jenis Pembebasan: ${r.jenisPem}`,
      `Pembebasan Bea Masuk: ${r.bm}`,
      `Fasilitas PDRI: ${r.pdri}`,
      `Syarat Fasilitas: ${r.syarat}`,
      `Regulasi: ${r.regulasi}`,
    ].join("\n\n");
  }

  /* ── Render ── */
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 32 }}>
      {/* ── STAT CARDS ── */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(3,1fr)",
          gap: 14,
        }}
      >
        {[
          {
            label: "Total Data Fasilitas",
            value: META.totalRecords.toLocaleString("id-ID"),
            teal: true,
          },
          {
            label: "Kode KBLI Tercakup",
            value: META.uniqueKbli.toLocaleString("id-ID"),
          },
          { label: "Sektor Kategori KBLI", value: META.uniqueKategori },
        ].map((stat, i) => (
          <div
            key={i}
            style={{
              background: stat.teal
                ? "linear-gradient(135deg,#0f766e,#0d9488)"
                : "#fff",
              border: "1px solid #e2e8f0",
              borderRadius: 16,
              padding: "16px 18px",
              boxShadow: "0 2px 8px rgba(15,23,42,0.06)",
            }}
          >
            <div
              style={{
                fontSize: 26,
                fontWeight: 900,
                letterSpacing: "-0.03em",
                color: stat.teal ? "#fff" : "#0f766e",
              }}
            >
              {stat.value}
            </div>
            <div
              style={{
                fontSize: 12,
                color: stat.teal ? "rgba(255,255,255,0.8)" : "#64748b",
                marginTop: 4,
                fontWeight: 600,
              }}
            >
              {stat.label}
            </div>
          </div>
        ))}
      </div>

      {/* ── MAIN LAYOUT ── */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "380px 1fr",
          gap: 20,
          alignItems: "start",
        }}
      >
        {/* ── LEFT PANEL: Input Form ── */}
        <div
          style={{
            background: "rgba(255,255,255,0.92)",
            border: "1px solid rgba(226,232,240,0.9)",
            borderRadius: 20,
            boxShadow: "0 14px 38px rgba(15,23,42,0.08)",
            backdropFilter: "blur(10px)",
            position: "sticky",
            top: 14,
            overflow: "hidden",
          }}
        >
          <div
            style={{
              padding: "20px 22px 16px",
              background:
                "linear-gradient(135deg,rgba(15,118,110,0.08),rgba(37,99,235,0.05))",
              borderBottom: "1px solid #e2e8f0",
            }}
          >
            <div
              style={{
                fontSize: 17,
                fontWeight: 800,
                color: "#172033",
                letterSpacing: "-0.02em",
              }}
            >
              Parameter Pencarian
            </div>
            <div
              style={{
                fontSize: 13,
                color: "#64748b",
                marginTop: 3,
                lineHeight: 1.5,
              }}
            >
              Pilih kategori KBLI, subkategori, lalu bidang usaha untuk melihat
              fasilitas pembebasan bea masuk.
            </div>
          </div>

          <div
            style={{
              padding: "20px 22px",
              display: "flex",
              flexDirection: "column",
              gap: 18,
            }}
          >
            {/* Kategori KBLI */}
            <div>
              <FieldLabel icon={Briefcase}>Kategori KBLI</FieldLabel>
              <SelectBox
                value={kategori}
                options={kategoriOptions}
                placeholder="Pilih kategori KBLI"
                onChange={(v) => {
                  setKategori(v);
                  setSubkategori("");
                  setBidangUsaha("");
                  setJenisBrg("");
                }}
              />
            </div>

            {/* Subkategori */}
            <div>
              <FieldLabel icon={Layers}>Subkategori KBLI</FieldLabel>
              <SelectBox
                value={subkategori}
                options={subkategoriOptions}
                placeholder={
                  kategori ? "Pilih subkategori" : "Pilih kategori dahulu"
                }
                disabled={!kategori}
                onChange={(v) => {
                  setSubkategori(v);
                  setBidangUsaha("");
                  setJenisBrg("");
                }}
              />
            </div>

            {/* Bidang Usaha */}
            <div>
              <FieldLabel icon={Tag}>Bidang Usaha KBLI 2025</FieldLabel>
              <SelectBox
                value={bidangUsaha}
                options={bidangUsahaOptions}
                placeholder={
                  subkategori
                    ? "Pilih bidang usaha"
                    : "Pilih subkategori dahulu"
                }
                disabled={!subkategori}
                onChange={(v) => {
                  setBidangUsaha(v);
                  setJenisBrg("");
                  setSelectedIndex(0);
                }}
              />
            </div>

            {/* Info box */}
            {!isLocked && (
              <div
                style={{
                  background: "#f0fdfa",
                  border: "1px solid #99f6e4",
                  borderRadius: 12,
                  padding: "10px 14px",
                  fontSize: 12.5,
                  color: "#0f766e",
                  lineHeight: 1.6,
                  display: "flex",
                  gap: 10,
                  alignItems: "flex-start",
                }}
              >
                <Info size={14} style={{ flexShrink: 0, marginTop: 2 }} />
                <span>
                  Pilih <strong>kategori → subkategori → bidang usaha</strong>{" "}
                  secara berurutan untuk menampilkan output fasilitas yang
                  sesuai.
                </span>
              </div>
            )}

            {/* Jenis Barang — hanya tampil kalau ada hasil */}
            {isLocked && jenisBrgOptions.length > 0 && (
              <div>
                <FieldLabel icon={Package}>Jenis Barang (filter)</FieldLabel>
                <SelectBox
                  value={jenisBrg}
                  options={jenisBrgOptions}
                  placeholder="Semua jenis barang"
                  onChange={(v) => {
                    setJenisBrg(v);
                    setSelectedIndex(0);
                  }}
                />
              </div>
            )}

            {/* Filter Tambahan */}
            {isLocked && (
              <details
                style={{
                  border: "1px dashed #cbd5e1",
                  borderRadius: 14,
                  padding: 14,
                  background: "#fbfdff",
                }}
              >
                <summary
                  style={{
                    cursor: "pointer",
                    fontWeight: 800,
                    color: "#334155",
                    fontSize: 13,
                  }}
                >
                  Filter Tambahan
                </summary>
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: 12,
                    marginTop: 14,
                  }}
                >
                  {[
                    {
                      label: "Kata Kunci Lokasi",
                      value: lokasi,
                      setter: setLokasi,
                      ph: "Contoh: Kalimantan",
                    },
                    {
                      label: "Kawasan Industri",
                      value: kawasan,
                      setter: setKawasan,
                      ph: "Contoh: KEK, KPBPB",
                    },
                    {
                      label: "HS Code / Pos Tarif",
                      value: hs,
                      setter: setHs,
                      ph: "Contoh: PMK, UU 17",
                    },
                  ].map((f) => (
                    <div key={f.label}>
                      <FieldLabel>{f.label}</FieldLabel>
                      <input
                        value={f.value}
                        onChange={(e) => {
                          f.setter(e.target.value);
                          setSelectedIndex(0);
                        }}
                        placeholder={f.ph}
                        style={{
                          width: "100%",
                          border: "1.5px solid #e2e8f0",
                          borderRadius: 12,
                          padding: "10px 13px",
                          fontSize: 13,
                          outline: "none",
                          fontFamily: "inherit",
                          boxSizing: "border-box",
                          background: "#fff",
                          transition: "border 0.15s, box-shadow 0.15s",
                        }}
                        onFocus={(e) => {
                          e.target.style.borderColor = "rgba(15,118,110,0.72)";
                          e.target.style.boxShadow =
                            "0 0 0 4px rgba(15,118,110,0.1)";
                        }}
                        onBlur={(e) => {
                          e.target.style.borderColor = "#e2e8f0";
                          e.target.style.boxShadow = "none";
                        }}
                      />
                    </div>
                  ))}
                </div>
              </details>
            )}

            {/* Actions */}
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr auto",
                gap: 10,
                marginTop: 4,
              }}
            >
              <button
                onClick={handleDownload}
                disabled={!filteredResults.length}
                style={{
                  padding: "12px 16px",
                  borderRadius: 12,
                  border: "none",
                  background: filteredResults.length
                    ? "linear-gradient(135deg,#0f766e,#0d9488)"
                    : "#e2e8f0",
                  color: filteredResults.length ? "#fff" : "#94a3b8",
                  fontSize: 13.5,
                  fontWeight: 700,
                  cursor: filteredResults.length ? "pointer" : "not-allowed",
                  fontFamily: "inherit",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  gap: 8,
                  boxShadow: filteredResults.length
                    ? "0 4px 14px rgba(15,118,110,0.28)"
                    : "none",
                  transition: "all 0.2s",
                }}
              >
                <Download size={14} /> Unduh JSON ({filteredResults.length})
              </button>
              <button
                onClick={resetAll}
                title="Reset semua filter"
                style={{
                  padding: "12px 14px",
                  borderRadius: 12,
                  border: "1.5px solid #e2e8f0",
                  background: "#fff",
                  cursor: "pointer",
                  color: "#64748b",
                  transition: "all 0.2s",
                  fontFamily: "inherit",
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = "#f8fafc";
                  e.currentTarget.style.color = "#334155";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = "#fff";
                  e.currentTarget.style.color = "#64748b";
                }}
              >
                <RefreshCcw size={15} />
              </button>
            </div>
          </div>
        </div>

        {/* ── RIGHT PANEL: Results + Detail ── */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Result Count Bar */}
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              gap: 12,
              flexWrap: "wrap",
            }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              <span
                style={{
                  display: "inline-flex",
                  padding: "6px 12px",
                  borderRadius: 999,
                  background: "#eff6ff",
                  border: "1px solid #bfdbfe",
                  color: "#1e40af",
                  fontSize: 12.5,
                  fontWeight: 800,
                }}
              >
                {isLocked
                  ? `${filteredResults.length.toLocaleString("id-ID")} hasil ditemukan`
                  : "Lengkapi kategori, subkategori, dan bidang usaha"}
              </span>
              {bidangUsaha && (
                <span style={{ fontSize: 13, color: "#64748b" }}>
                  KBLI{" "}
                  <strong style={{ color: "#0f766e" }}>{bidangUsaha}</strong>
                </span>
              )}
            </div>
            {selected && <CopyButton text={summarize(selected)} />}
          </div>

          {/* Empty state */}
          {!isLocked && (
            <motion.div
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              style={{
                background: "rgba(255,255,255,0.88)",
                border: "1px solid rgba(226,232,240,0.9)",
                borderRadius: 20,
                boxShadow: "0 14px 38px rgba(15,23,42,0.08)",
                minHeight: 420,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                justifyContent: "center",
                textAlign: "center",
                padding: 40,
              }}
            >
              <div
                style={{
                  width: 68,
                  height: 68,
                  borderRadius: "50%",
                  background: "#f0fdfa",
                  border: "2px solid #99f6e4",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  marginBottom: 18,
                }}
              >
                <Search size={30} color="#0f766e" />
              </div>
              <div
                style={{
                  fontSize: 18,
                  fontWeight: 800,
                  color: "#172033",
                  marginBottom: 8,
                  letterSpacing: "-0.02em",
                }}
              >
                Siap Menganalisis Fasilitas
              </div>
              <p
                style={{
                  fontSize: 13.5,
                  color: "#94a3b8",
                  maxWidth: 320,
                  lineHeight: 1.7,
                  margin: 0,
                }}
              >
                Pilih kategori KBLI, subkategori, dan bidang usaha di panel kiri
                untuk melihat output fasilitas pembebasan bea masuk yang
                tersedia.
              </p>
            </motion.div>
          )}

          {/* No results */}
          {isLocked && filteredResults.length === 0 && (
            <motion.div
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              style={{
                background: "#fef2f2",
                border: "1.5px solid #fecaca",
                borderRadius: 16,
                padding: "18px 22px",
                display: "flex",
                gap: 14,
                alignItems: "flex-start",
              }}
            >
              <XCircle
                size={22}
                color="#ef4444"
                style={{ flexShrink: 0, marginTop: 2 }}
              />
              <div>
                <div
                  style={{
                    fontSize: 14,
                    fontWeight: 700,
                    color: "#dc2626",
                    marginBottom: 4,
                  }}
                >
                  Tidak Ada Data Ditemukan
                </div>
                <div
                  style={{ fontSize: 13, color: "#b91c1c", lineHeight: 1.6 }}
                >
                  Kombinasi parameter yang dipilih tidak memiliki data
                  fasilitas. Coba kurangi filter tambahan atau pilih bidang
                  usaha yang berbeda.
                </div>
              </div>
            </motion.div>
          )}

          {/* Results grid */}
          {isLocked && filteredResults.length > 0 && (
            <div
              style={{ display: "grid", gridTemplateColumns: "1fr", gap: 10 }}
              ref={resultsRef}
            >
              {filteredResults.slice(0, 20).map((r, i) => (
                <motion.div
                  key={r.row}
                  initial={{ opacity: 0, y: 6 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.04 }}
                  onClick={() => {
                    setSelectedIndex(i);
                    setExpandedDetail(true);
                  }}
                  style={{
                    background:
                      i === safeIndex
                        ? "linear-gradient(0deg,rgba(236,253,245,0.76),#fff)"
                        : "#fff",
                    border: `1.5px solid ${i === safeIndex ? "rgba(15,118,110,0.45)" : "#e2e8f0"}`,
                    borderRadius: 16,
                    padding: "16px 18px",
                    cursor: "pointer",
                    boxShadow:
                      i === safeIndex
                        ? "0 8px 22px rgba(15,23,42,0.08)"
                        : "0 2px 6px rgba(15,23,42,0.04)",
                    transition: "all 0.18s",
                  }}
                  onMouseEnter={(e) => {
                    if (i !== safeIndex) {
                      e.currentTarget.style.borderColor =
                        "rgba(15,118,110,0.3)";
                      e.currentTarget.style.transform = "translateY(-1px)";
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (i !== safeIndex) {
                      e.currentTarget.style.borderColor = "#e2e8f0";
                      e.currentTarget.style.transform = "none";
                    }
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "flex-start",
                      gap: 12,
                      marginBottom: 8,
                    }}
                  >
                    <div>
                      <div
                        style={{
                          fontWeight: 900,
                          fontSize: 18,
                          letterSpacing: "-0.015em",
                          color: "#172033",
                        }}
                      >
                        {r.kode}
                      </div>
                      <div
                        style={{
                          fontWeight: 700,
                          fontSize: 14,
                          lineHeight: 1.35,
                          color: "#334155",
                          marginTop: 2,
                        }}
                      >
                        {r.bidang}
                      </div>
                    </div>
                    <Chip variant="green">{r.jenisBrg}</Chip>
                  </div>
                  <div
                    style={{
                      fontSize: 12,
                      color: "#64748b",
                      lineHeight: 1.45,
                      marginBottom: 10,
                    }}
                  >
                    {compact(r.kat, 100)}
                  </div>
                  <div style={{ display: "flex", gap: 7, flexWrap: "wrap" }}>
                    <Chip variant="teal">{compact(r.jenisPem, 40)}</Chip>
                    <Chip variant="orange">Baris Excel: {r.row}</Chip>
                  </div>
                </motion.div>
              ))}
              {filteredResults.length > 20 && (
                <div
                  style={{
                    textAlign: "center",
                    fontSize: 13,
                    color: "#94a3b8",
                    padding: "8px 0",
                  }}
                >
                  Menampilkan 20 dari {filteredResults.length} hasil. Gunakan
                  filter tambahan untuk mempersempit.
                </div>
              )}
            </div>
          )}

          {/* ── DETAIL PANEL ── */}
          <AnimatePresence>
            {selected && (
              <motion.div
                key={selected.row}
                initial={{ opacity: 0, y: 12 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 8 }}
                style={{
                  background: "rgba(255,255,255,0.94)",
                  border: "1px solid rgba(226,232,240,0.9)",
                  borderRadius: 20,
                  boxShadow: "0 14px 38px rgba(15,23,42,0.08)",
                  backdropFilter: "blur(10px)",
                  overflow: "hidden",
                }}
              >
                {/* Detail Header */}
                <div
                  style={{
                    padding: "20px 22px",
                    cursor: "pointer",
                    userSelect: "none",
                    background:
                      "linear-gradient(135deg,rgba(15,118,110,0.1),rgba(37,99,235,0.06))",
                    borderBottom: "1px solid rgba(15,118,110,0.15)",
                    display: "flex",
                    alignItems: "flex-start",
                    justifyContent: "space-between",
                    gap: 16,
                  }}
                  onClick={() => setExpandedDetail((e) => !e)}
                >
                  <div>
                    <h2
                      style={{
                        margin: "0 0 8px",
                        fontSize: 20,
                        fontWeight: 900,
                        letterSpacing: "-0.03em",
                        lineHeight: 1.18,
                        color: "#172033",
                      }}
                    >
                      {selected.kode} — {selected.bidang}
                    </h2>
                    <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                      <Chip variant="green">{selected.jenisBrg}</Chip>
                      <Chip variant="teal">
                        {compact(selected.jenisPem, 50)}
                      </Chip>
                    </div>
                  </div>
                  <div style={{ flexShrink: 0, color: "#64748b" }}>
                    {expandedDetail ? (
                      <ChevronUp size={20} />
                    ) : (
                      <ChevronDown size={20} />
                    )}
                  </div>
                </div>

                <AnimatePresence>
                  {expandedDetail && (
                    <motion.div
                      initial={{ height: 0, opacity: 0 }}
                      animate={{ height: "auto", opacity: 1 }}
                      exit={{ height: 0, opacity: 0 }}
                      transition={{ duration: 0.25 }}
                      style={{ overflow: "hidden" }}
                    >
                      <div
                        style={{
                          padding: "20px 22px",
                          display: "flex",
                          flexDirection: "column",
                          gap: 14,
                        }}
                      >
                        <DetailSection title="Output Utama">
                          <DetailField
                            label="Jenis Pembebasan"
                            value={selected.jenisPem}
                            accent="#0f766e"
                          />
                          <DetailField
                            label="Cakupan Barang"
                            value={selected.cakupanBrg}
                          />
                          <DetailField
                            label="Pembebasan Bea Masuk"
                            value={selected.bm}
                            accent="#059669"
                          />
                          <DetailField
                            label="Fasilitas PDRI Lainnya"
                            value={selected.pdri}
                          />
                          <DetailField
                            label="Syarat Fasilitas"
                            value={selected.syarat}
                          />
                          <DetailField
                            label="Keterangan Tambahan"
                            value={selected.ket}
                            accent="#92400e"
                          />
                        </DetailSection>

                        <DetailSection title="Kepatuhan & Regulasi">
                          <DetailField
                            label="Catatan Legal Compliance"
                            value={selected.compliance}
                          />
                          <DetailField
                            label="Rujukan Regulasi Utama"
                            value={selected.regulasi}
                            accent="#1e40af"
                          />
                          <DetailField
                            label="Insentif Tambahan"
                            value={selected.insentif}
                            accent="#065f46"
                          />
                        </DetailSection>

                        <DetailSection title="Pemetaan Kolom">
                          <DetailField
                            label="Input Utama"
                            value="Kategori KBLI, Subkategori KBLI, Kode KBLI / Bidang Usaha, Jenis Barang"
                          />
                          <DetailField
                            label="Input Tambahan / Filter"
                            value="Kawasan Industri, Pos Tarif / HS Code, Kata Kunci Lokasi"
                          />
                          <DetailField
                            label="Logika Tampilan"
                            value="Kategori mengunci subkategori → subkategori mengunci bidang usaha → bidang usaha memicu output sesuai baris data yang cocok."
                          />
                        </DetailSection>
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </div>
  );
}
